const MODULE_META = {
  xabcd: { label: "1. xABCDE" },
  labor: { label: "2. Laborwerte" },
  med: { label: "3. Medikamente" },
  ekg: { label: "4. EKG Kurs" },
  ludwig: { label: "5. Dr. Ludwig" },
  miranda: { label: "6. Miranda de Queiroz" },
  wrong: { label: "7. Meine Schwächen" }
};

const appState = {
  mode: "learning",
  activeModule: null,
  currentQuestions: [],
  reviewQuestions: [],
  index: 0,
  score: 0,
  firstPassTotal: 0,
  totalAsked: 0,
  jokerUsed: false,
  timer: null,
  timeLeft: 25
};

const wrongBank = [];

function setMode(mode) {
  appState.mode = mode;
  document.getElementById("modeLearningBtn").classList.toggle("active", mode === "learning");
  document.getElementById("modeExamBtn").classList.toggle("active", mode === "exam");
}

function showScreen(id) {
  document.querySelectorAll(".screen").forEach(el => el.classList.remove("active"));
  document.getElementById(id).classList.add("active");
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function openHome() {
  showScreen("homeScreen");
}

function goHome() {
  stopTimer();
  showScreen("homeScreen");
}

function shuffleArray(arr) {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

function prepareQuestions(list) {
  return shuffleArray(deepClone(list)).map(q => {
    const opts = q.antworten.map((txt, idx) => ({ txt, idx }));
    const mixed = shuffleArray(opts);
    const correctIndex = mixed.findIndex(a => a.idx === q.richtig);
    return {
      frage: q.frage,
      antworten: mixed.map(a => a.txt),
      richtig: correctIndex,
      image: q.image || null,
      erklaerung: q.erklaerung || ""
    };
  });
}

function startQuiz(moduleKey) {
  let source;
  if (moduleKey === "wrong") {
    source = wrongBank;
  } else {
    source = QUESTIONS[moduleKey] || [];
  }

  if (!source.length) {
    alert("Für dieses Modul sind aktuell keine Fragen vorhanden.");
    return;
  }

  appState.activeModule = moduleKey;
  appState.currentQuestions = prepareQuestions(source);
  appState.reviewQuestions = [];
  appState.index = 0;
  appState.score = 0;
  appState.firstPassTotal = appState.currentQuestions.length;
  appState.totalAsked = 0;
  appState.jokerUsed = false;

  document.getElementById("moduleLabel").innerText = MODULE_META[moduleKey].label;
  document.getElementById("scoreText").innerText = "Richtig: 0";
  document.getElementById("jokerBtn").disabled = false;
  document.getElementById("jokerBtn").classList.remove("hidden");
  showScreen("quizScreen");
  renderQuestion();
}

function renderQuestion() {
  if (appState.index >= appState.currentQuestions.length) {
    if (appState.reviewQuestions.length) {
      appState.currentQuestions = shuffleArray(appState.reviewQuestions);
      appState.reviewQuestions = [];
      appState.index = 0;
      alert("Jetzt kommen die noch nicht sicheren Fragen erneut.");
    } else {
      finishQuiz();
      return;
    }
  }

  const q = appState.currentQuestions[appState.index];
  appState.totalAsked++;
  appState.timeLeft = 25;
  stopTimer();
  startTimer();

  document.getElementById("counter").innerText = "Frage " + (appState.index + 1) + " von " + appState.currentQuestions.length;
  document.getElementById("progressBar").style.width = (((appState.index + 1) / appState.currentQuestions.length) * 100) + "%";
  document.getElementById("question").innerText = q.frage;
  document.getElementById("feedback").innerText = "";
  document.getElementById("explanation").innerText = q.erklaerung || "";
  document.getElementById("explanation").classList.toggle("hidden", appState.mode !== "learning" || !q.erklaerung);
  document.getElementById("nextBtn").classList.add("hidden");
  document.getElementById("jokerBtn").classList.toggle("hidden", appState.jokerUsed);

  const imageWrap = document.getElementById("imageWrap");
  const image = document.getElementById("questionImage");
  if (q.image) {
    image.src = q.image;
    imageWrap.classList.remove("hidden");
  } else {
    image.src = "";
    imageWrap.classList.add("hidden");
  }

  const answers = document.getElementById("answers");
  answers.innerHTML = "";
  q.antworten.forEach((antwort, idx) => {
    const btn = document.createElement("button");
    btn.className = "answer-btn";
    btn.innerText = antwort;
    btn.onclick = () => evaluateAnswer(idx);
    answers.appendChild(btn);
  });
}

function evaluateAnswer(selectedIndex) {
  const q = appState.currentQuestions[appState.index];
  stopTimer();
  const buttons = [...document.querySelectorAll(".answer-btn")];
  buttons.forEach(btn => btn.classList.add("disabled"));

  buttons.forEach((btn, idx) => {
    if (idx === q.richtig) btn.classList.add("correct");
  });

  if (selectedIndex === q.richtig) {
    appState.score++;
    document.getElementById("feedback").innerText = "Richtig";
    playCorrectSound();
  } else {
    buttons[selectedIndex].classList.add("wrong");
    document.getElementById("feedback").innerText = "Falsch";
    appState.reviewQuestions.push(q);
    wrongBank.push(q);
    playWrongSound();
  }

  document.getElementById("scoreText").innerText = "Richtig: " + appState.score;
  document.getElementById("nextBtn").classList.remove("hidden");
  if (appState.mode !== "learning") {
    document.getElementById("explanation").classList.add("hidden");
  }
}

function nextQuestion() {
  appState.index++;
  renderQuestion();
}

function restartQuiz() {
  if (!appState.activeModule) {
    openHome();
    return;
  }
  startQuiz(appState.activeModule);
}

function finishQuiz() {
  stopTimer();
  const percent = Math.round((appState.score / appState.firstPassTotal) * 100);
  document.getElementById("resultTitle").innerText = MODULE_META[appState.activeModule].label + " abgeschlossen";
  document.getElementById("resultText").innerText =
    "Direkt richtig beantwortet: " + appState.score + " von " + appState.firstPassTotal +
    ". Ergebnis im ersten Durchgang: " + percent + " Prozent. Insgesamt gestellte Fragen inklusive Wiederholungen: " +
    appState.totalAsked + ".";
  showScreen("resultScreen");
}

function startTimer() {
  document.getElementById("timer").innerText = "Zeit: " + appState.timeLeft;
  appState.timer = setInterval(() => {
    appState.timeLeft--;
    document.getElementById("timer").innerText = "Zeit: " + appState.timeLeft;
    if (appState.timeLeft <= 0) {
      stopTimer();
      handleTimeout();
    }
  }, 1000);
}

function stopTimer() {
  if (appState.timer) {
    clearInterval(appState.timer);
    appState.timer = null;
  }
}

function handleTimeout() {
  const q = appState.currentQuestions[appState.index];
  document.getElementById("feedback").innerText = "Zeit abgelaufen";
  document.getElementById("nextBtn").classList.remove("hidden");
  appState.reviewQuestions.push(q);
  wrongBank.push(q);

  const buttons = [...document.querySelectorAll(".answer-btn")];
  buttons.forEach(btn => btn.classList.add("disabled"));
  buttons.forEach((btn, idx) => {
    if (idx === q.richtig) btn.classList.add("correct");
  });
  playWrongSound();
}

function useJoker() {
  if (appState.jokerUsed) return;
  const q = appState.currentQuestions[appState.index];
  const buttons = [...document.querySelectorAll(".answer-btn")];
  const wrongButtons = buttons.filter((_, idx) => idx !== q.richtig && !buttons[idx].classList.contains("removed"));
  if (!wrongButtons.length) return;
  const removeOne = wrongButtons[Math.floor(Math.random() * wrongButtons.length)];
  removeOne.classList.add("removed");
  appState.jokerUsed = true;
  document.getElementById("jokerBtn").classList.add("hidden");
}

function playTone(freq, type, duration, gainValue, endFreq = null) {
  const AudioCtx = window.AudioContext || window.webkitAudioContext;
  if (!AudioCtx) return;
  const ctx = new AudioCtx();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = type;
  osc.frequency.setValueAtTime(freq, ctx.currentTime);
  if (endFreq) osc.frequency.exponentialRampToValueAtTime(endFreq, ctx.currentTime + duration / 1000);
  gain.gain.setValueAtTime(gainValue, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration / 1000);
  osc.connect(gain).connect(ctx.destination);
  osc.start();
  osc.stop(ctx.currentTime + duration / 1000 + 0.02);
}

function playCorrectSound() {
  playTone(740, "sine", 120, 0.06);
  setTimeout(() => playTone(988, "sine", 180, 0.06), 110);
}

function playWrongSound() {
  playTone(280, "sawtooth", 180, 0.05, 180);
  setTimeout(() => playTone(220, "triangle", 220, 0.05, 140), 120);
}

document.addEventListener("DOMContentLoaded", () => {
  setMode("learning");
});
